1	// Shared render-surface primitives — the single source of truth for the bits every render surface
2	// (sticky, inline comment, review body) must agree on: the severity→emoji mapping, the
3	// machine-readable findings-json pointer (issue #19), and the patch→suggestion projection. Pure.
4	
5	import type { Finding, Findings } from "./schema.js";
6	import { patchToSuggestion } from "./patch.js";
7	
8	/** Severity → emoji, used by every render surface (sticky, inline, strays). */
9	export const severityEmoji = (s: string): string => {
10	  switch (s) {
11	    case "critical":
12	      return "🔴";
13	    case "major":
14	      return "🟠";
15	    case "minor":
16	      return "🔵";
17	    case "nit":
18	      return "⚪";
19	    default:
20	      return "❓";
21	  }
22	};
23	
24	/** Base64 chars (~30KB JSON); keeps a comment well under GitHub's 65536-char comment limit. */
25	const EMBED_LIMIT = 40000;
26	
27	/** The directive that makes the marker below self-describing to a reviewing agent — travels with
28	 *  the marker on every surface so a reader who only sees one comment still knows to decode it. */
29	const AGENTS_STOP_DIRECTIVE =
30	  "<!-- AGENTS: STOP — do not parse the prose below; decode this findings JSON and read schema_version first. -->";
31	
32	/** Shared core of the findings-json marker: base64-encodes `document` when it fits under `limit`,
33	 *  falls back to a `jsonUrl` link marker, or omits the marker entirely when neither is available —
34	 *  prefixed with the AGENTS_STOP directive whenever a marker is produced. */
35	const encodeMarker = (document: unknown, jsonUrl: string | undefined, limit: number): string => {
36	  const b64 = Buffer.from(JSON.stringify(document), "utf-8").toString("base64");
37	  const marker =
38	    b64.length <= limit
39	      ? `<!-- code-review:findings-json;base64 ${b64} -->`
40	      : jsonUrl
41	        ? `<!-- code-review:findings-json ${jsonUrl} -->`
42	        : "";
43	  return marker ? `${AGENTS_STOP_DIRECTIVE}\n${marker}` : "";
44	};
45	
46	/** The machine-readable findings-json marker (issue #19), identical on the sticky and the review
47	 *  body: embeds the whole `findings` document as base64 when it fits under `limit`, falls back to a
48	 *  `jsonUrl` link marker, or omits the marker entirely when neither is available. */
49	export const findingsPointer = (
50	  findings: Findings,
51	  jsonUrl: string | undefined,
52	  limit = EMBED_LIMIT,
53	): string => encodeMarker(findings, jsonUrl, limit);
54	
55	/** The per-finding counterpart to {@link findingsPointer} (issue #31): each inline comment embeds
56	 *  only its own `finding` (with `schemaVersion`), not the entire findings document — the sticky and
57	 *  review body remain the whole-document SSOT. Same base64/limit/jsonUrl-fallback/AGENTS_STOP
58	 *  behavior as `findingsPointer`. */
59	export const findingPointer = (
60	  finding: Finding,
61	  schemaVersion: string,
62	  jsonUrl?: string,
63	  limit = EMBED_LIMIT,
64	): string => encodeMarker({ schema_version: schemaVersion, findings: [finding] }, jsonUrl, limit);
65	
66	/** The inverse of {@link findingsPointer}'s base64 form: extract and decode the whole-document
67	 *  findings JSON a prior run embedded in a sticky/review body, or null when the body carries no
68	 *  base64 marker (e.g. the jsonUrl-link fallback used for oversized findings, which can't be decoded
69	 *  inline) or the payload isn't valid JSON. Returns the raw decoded value — callers validate it
70	 *  against the current schema before trusting it (a prior run may predate the current shape). Pure. */
71	export const parseFindingsMarker = (body: string): unknown => {
72	  const match = /<!-- code-review:findings-json;base64 ([A-Za-z0-9+/=]+) -->/.exec(body);
73	  const b64 = match?.[1];
74	  if (b64 === undefined) return null;
75	  try {
76	    return JSON.parse(Buffer.from(b64, "base64").toString("utf-8"));
77	  } catch {
78	    return null;
79	  }
80	};
81	
82	/** Escape triple-backtick sequences so fenced content can't break out of its block. */
83	const escapeFence = (text: string): string => text.replace(/```/g, "`` ` ``");
84	
85	/** How a finding's `patch` renders on a surface (JP's core design): a GitHub ```suggestion when the
86	 *  patch lowers to replacement text (anchored at the finding's already-aligned range), a raw
87	 *  ```patch fallback when it can't lower (non-lossy — the diff still reaches the reader), or nothing
88	 *  when the finding carries no patch. Fenced content is backtick-escaped against breakout. */
89	export type PatchProjection =
90	  | { readonly kind: "suggestion"; readonly text: string }
91	  | { readonly kind: "patch"; readonly raw: string }
92	  | { readonly kind: "none" };
93	
94	/** Project a finding's `patch` into a template-ready {@link PatchProjection}. Pure. */
95	export const projectPatch = (patch: string | undefined): PatchProjection => {
96	  if (patch === undefined) return { kind: "none" };
97	  const lowered = patchToSuggestion(patch);
98	  return typeof lowered === "string"
99	    ? { kind: "suggestion", text: escapeFence(lowered) }
100	    : { kind: "patch", raw: escapeFence(patch) };
101	};
102	
103	/** Confidence, always at 2 decimal places (issue #26 — `1` renders `1.00`, `0.6` renders `0.60`). */
104	export const formatConfidence = (n: number): string => n.toFixed(2);
105	
106	/** The review-object body: the shared findings-json marker (when present) followed by a one-line
107	 *  pointer to the sticky summary, linking to it when its URL is known. The single source of truth
108	 *  for this body, shared by the commenter (post.ts) and the `preview` command. Pure. */
109	export const reviewBodyPointer = (
110	  headSha: string,
111	  stickyUrl: string | undefined,
112	  marker: string,
113	): string => {
114	  const sha7 = headSha.slice(0, 7);
115	  const linkLine = stickyUrl
116	    ? `🤖 Automated code review for \`${sha7}\` — see the [summary comment](${stickyUrl}) for the verdict, walkthrough, and cost.`
117	    : `🤖 Automated code review for \`${sha7}\` — see the summary comment for the verdict, walkthrough, and cost.`;
118	  return marker ? `${marker}\n\n${linkLine}` : linkLine;
119	};
