1	// The `gh api` effect: the single shell boundary for GitHub API calls. Pure callers inject a
2	// fake; the default implementation shells out to the `gh` CLI (auth via GH_TOKEN in the env).
3	
4	import { execFile } from "node:child_process";
5	
6	/** Signature of the `gh api` effect. Default implementation shells out to the `gh` CLI. */
7	export type GhApi = (
8	  args: readonly string[],
9	  stdin?: string,
10	  env?: Readonly<Record<string, string>>,
11	) => Promise<string>;
12	
13	/** Default effect: execFile gh. Extra `env` merges over process.env for this call only —
14	 *  used to pass untrusted values (bot login, marker) to jq via `env.NAME`, never interpolated
15	 *  into the filter text (SPEC §5.4). */
16	export const runGhApi: GhApi = (args, stdin, env) =>
17	  new Promise<string>((resolve, reject) => {
18	    const child = execFile(
19	      "gh",
20	      ["api", ...args],
21	      { env: { ...process.env, ...env }, encoding: "utf-8", maxBuffer: 100 * 1024 * 1024 },
22	      (err, stdout, stderr) => {
23	        if (err) {
24	          const stderrStr = typeof stderr === "string" && stderr.trim() ? stderr.trim() : "";
25	          const errStr = err instanceof Error ? err.message : "unknown error";
26	          reject(new Error(`gh api failed: ${stderrStr || errStr}`));
27	        } else {
28	          resolve(stdout);
29	        }
30	      },
31	    );
32	    if (stdin !== undefined) {
33	      child.stdin?.end(stdin);
34	    }
35	  });
